function addAndSearchWord(data) {
    const text = (data || '').trim();
    if (!text) return 'None';

    const tokens = text.split(/\s+/);
    const words = [];
    const out = [];

    const matches = (word, pattern) => {
        if (word.length !== pattern.length) return false;
        for (let i = 0; i < word.length; i++) {
            if (pattern[i] !== '.' && pattern[i] !== word[i]) return false;
        }
        return true;
    };

    let i = 0;
    while (i < tokens.length) {
        const op = tokens[i++];
        if (op === 'addWord' && i < tokens.length) {
            words.push(tokens[i++]);
            continue;
        }
        if (op === 'search' && i < tokens.length) {
            const pat = tokens[i++];
            const ok = words.some((w) => matches(w, pat));
            out.push(ok ? 'true' : 'false');
        }
    }

    return out.length ? out.join(' ') : 'None';
}

