func NewTrie() *Trie {
    return &Trie{root: &TrieNode{children: make(map[rune]*TrieNode)}}
}

func (t *Trie) Insert(word string) {
    node := t.root
    for _, ch := range word {
        if _, exists := node.children[ch]; !exists {
            node.children[ch] = &TrieNode{children: make(map[rune]*TrieNode)}
        }
        node = node.children[ch]
    }
    node.isEnd = true
}

func (t *Trie) Search(word string) bool {
    return t.searchHelper(t.root, word, 0)
}

func (t *Trie) searchHelper(node *TrieNode, word string, index int) bool {
    if index == len(word) {
        return node.isEnd
    }
    ch := rune(word[index])
    if ch == '.' {
        for _, child := range node.children {
            if t.searchHelper(child, word, index+1) {
                return true
            }
        }
        return false
    } else {
        if child, exists := node.children[ch]; exists {
            return t.searchHelper(child, word, index+1)
        }
        return false
    }
